sp_angular_provider.script:
function dtBreadcrumbs($rootScope, $location) {
	sessionStorage.setItem('breadcrumbs', '[]');
	function insert(newCrumbs) {

		sessionStorage.setItem('customCrumbs', JSON.stringify(false));

		var oldCrumbs = JSON.parse(sessionStorage.getItem('breadcrumbs')) || [];
		if (!newCrumbs) {
			newCrumbs = [{
				label: document.title.slice(0, -16),
				url: location.href
			}];
		} else {
			sessionStorage.setItem('customCrumbs', JSON.stringify(true));
		}


		var index = -1,
			crumb = newCrumbs[0];
		for (var i = 0; i < oldCrumbs.length; ++i) {
			if (crumb.label === oldCrumbs[i].label) {
				index = i;
				break;
			}
		}
		if (index !== -1) oldCrumbs.splice(index);
		newCrumbs.forEach(function(crumb) {
			oldCrumbs.push(crumb);
		});
		sessionStorage.setItem('breadcrumbs', JSON.stringify(oldCrumbs));
	}

	$rootScope.$on('$locationChangeSuccess', function(event, newUrl, oldUrl) {
		if (oldUrl.includes('id=discovertasker_portal')) {
			sessionStorage.setItem('breadcrumbs', '[]');
			sessionStorage.setItem('customCrumbs', JSON.stringify(false));
		} else if (!JSON.parse(sessionStorage.getItem('customCrumbs')) 
				   && !$rootScope.page.title.includes('New Item')) {
			insert();
		}
	});

	return {
		insert: insert,
		get: function() { return JSON.parse(sessionStorage.getItem('breadcrumbs')); },
		pop: function() {
			var breadcrumbs = JSON.parse(sessionStorage.getItem('breadcrumbs')),
				result = breadcrumbs.pop();
			sessionStorage.setItem('breadcrumbs', JSON.stringify(breadcrumbs));
			return result;
		}
	};
}
